  private val dangerousPatterns: Set[String] = Set(
    ";", "&&", "||", "|", "`", "$(", "${",
    ">", ">>", "<", "<<",
    "\n", "\r", "\u0000",
    "&", "!", "{", "}"
  )

  // Validate that a single argument contains no injection characters
  private def isValidArgument(arg: String): Boolean = {
    !dangerousPatterns.exists(pattern => arg.contains(pattern))
  }

  // Validate the command is in the whitelist
  private def isAllowedCommand(command: String): Boolean = {
    allowedCommands.contains(command)
  }

  // Sanitize an argument by rejecting dangerous characters
  private def validateArgument(arg: String): Either[String, String] = {
    if (arg.isEmpty) {
      Left("Empty argument not allowed")
    } else if (!isValidArgument(arg)) {
      Left(s"Argument contains disallowed characters: $arg")
    } else {
      Right(arg)
    }
