  /**
   * Safely execute a command with arguments.
   * Uses Process with a sequence of strings (command + args) to avoid shell interpretation.
   * This prevents command injection because arguments are passed directly to the process
   * without going through a shell.
   *
   * @param command The base command to execute (must be whitelisted)
   * @param args    The arguments to pass to the command
   * @return Either an error message or the command output
   */
  def executeCommand(command: String, args: List[String]): Either[String, String] = {
    // Step 1: Validate the command is whitelisted
    if (!isAllowedCommand(command)) {
      return Left(s"Command '$command' is not in the allowed commands list. Allowed: ${allowedCommands.mkString(", ")}")
    }

    // Step 2: Validate each argument
    val validatedArgs: Either[String, List[String]] = {
      val results = args.map(validateArgument)
      val errors = results.collect { case Left(err) => err }
      if (errors.nonEmpty) {
        Left(s"Invalid arguments: ${errors.mkString("; ")}")
      } else {
        Right(results.collect { case Right(arg) => arg })
      }
    }

    validatedArgs match {
      case Left(error) => Left(error)
      case Right(safeArgs) =>
        // Step 3: Use Process with a Seq[String] to avoid shell interpretation entirely.
        // This is the KEY defense against command injection:
        // Instead of: s"$command ${args.mkString(" ")}".!!  (DANGEROUS - shell interprets metacharacters)
        // We use:     Process(Seq(command) ++ args)          (SAFE - no shell involved)
        val commandSeq: Seq[String] = Seq(command) ++ safeArgs

        Try {
          val processBuilder = Process(commandSeq)
          val output = new StringBuilder
          val errorOutput = new StringBuilder

          val exitCode = processBuilder ! ProcessLogger(
            line => output.append(line).append("\n"),
            line => errorOutput.append(line).append("\n")
          )

          if (exitCode == 0) {
            output.toString().trim
          } else {
            throw new RuntimeException(
              s"Command exited with code $exitCode. Stderr: ${errorOutput.toString().trim}"
