        val showAll = if (params.getOrElse("showHidden", "false") == "true") List("-la") else List("-l")
        executeCommand("ls", showAll :+ path)

      case "process-list" =>
        executeCommand("ps", List("aux"))

      case "system-info" =>
        executeCommand("uname", List("-a"))

      case "memory-usage" =>
        executeCommand("free", List("-h"))

      case "check-service" =>
        params.get("service") match {
