      case "find-files" =>
        val path = params.getOrElse("path", ".")
        val name = params.getOrElse("name", "*")
        executeCommand("find", List(path, "-name", name, "-maxdepth", "3"))

      case "search-in-file" =>
        (params.get("pattern"), params.get("file")) match {
          case (Some(pattern), Some(file)) =>
            executeCommand("grep", List("-n", pattern, file))
          case _ =>
            Left("Missing required parameters: pattern, file")
        }

      case _ =>
        Left(s"Unknown task: $taskName. Available tasks: disk-usage, list-files, process-list, system-info, memory-usage, check-service, view-logs, docker-ps, find-files, search-in-file")
    }
  }
